const systems=[
{id:'tap-current',section:'Tap Effects',title:'Current tap-effect loadout',pages:'6-17',status:'shipped',summary:'A cosmetic effect slot exists with Shockring, Starburst, Ripple, and No Effect.',requirements:['One equipped effect at a time','No effect may change physics, rewards, spawns, or competitive outcomes','Ownership and equipped selection persist'],evidence:'Implemented in the shared store catalog and the in-game store/equipment UI. The bible’s larger environmental effect framework is a separate pending record.'},
{id:'tap-rings',section:'Tap Effects',title:'Pulsing Rings and color variants',pages:'6-7',status:'pending',summary:'Expanding rings with purple base, unlockable custom colors, and a premium RGB mode.',requirements:['Base purple ring: 100 Hero Coins','Custom color/slot: 50 coins with hue, saturation, brightness, RGB, darkness, and safe opacity','RGB version: 300 coins; Random RGB, Smooth Rainbow, or Custom Palette','Avoid rapid flashing'],evidence:'The current Shockring is a simpler catalog effect. The configurable system specified here is not implemented.'},
{id:'tap-weather',section:'Tap Effects',title:'Rain, snow, and rare events',pages:'7-9',status:'pending',summary:'Localized rain and snow that accumulate temporarily and can trigger rare cosmetic encounters.',requirements:['Rain: 200 coins; 0.001% lightning chance per tap','Lightning creates controlled flash, thunder, temporary scorch, smoke, and reactions without damage','Snow: 200 coins; staged accumulation with capped piles and melting','Evil Snowman check occurs when a qualifying threshold is crossed, suggested 3-5%'],evidence:'No environmental accumulation manager or rare weather event scenes are present in the current game.'},
{id:'tap-magma',section:'Tap Effects',title:'Magma, fire, and autumn leaves',pages:'9-11',status:'pending',summary:'Accumulating molten pools, quick fire bursts, and leaf piles that react visually to landings.',requirements:['Magma: 200 coins; stages from splash through obsidian remains','Obsidian Golem threshold event, cosmetic only','Fire: 75 coins as an affordable first cosmetic','Leaves: 200 coins; temporary piles burst when entered'],evidence:'Specified in the bible; not present in the current catalog or scene tree.'},
{id:'tap-architecture',section:'Tap Effects',title:'Effect architecture and performance',pages:'11-17',status:'pending',summary:'Data-driven managers, pooled instances, accumulation zones, quality levels, multiplayer reduction, and accessibility settings.',requirements:['TapEffectManager and definition data separate gameplay from cosmetics','Full, Reduced, Minimal, and Off quality settings','Client-side piles and owner-focused rare creatures in multiplayer','Controls for density, opacity, shake, flash, sound, haptics, and other-player effects'],evidence:'The existing catalog establishes ownership slots, but the proposed effect runtime, pooling, accumulation, and quality controls are not built.'},
{id:'tap-ideas',section:'Tap Effects',title:'Extended tap-effect concept library',pages:'18-26',status:'concept',summary:'Thirty-plus interactive concepts ranging from bubbles and portals to paint, music, footprints, fireworks, and companions.',requirements:['Simple effects target 75-100 coins','Movement/variation effects target 125-175 coins','Accumulation or rare-event effects target 200-250 coins','Highly customizable premium effects target 300-400 coins','Prioritize environmental memory, hidden reactions, and satisfying chains'],evidence:'Concept pool for future selection, not a committed implementation list.'},
{id:'particles-system',section:'Character Particles',title:'Character particle-effect system',pages:'28-29',status:'pending',summary:'A cosmetic slot attached to the character during movement, idle, jumping, landing, and elimination.',requirements:['Distinct from tap effects and follows the player','One primary effect, with optional compatible secondary components','Cannot obscure collision position or provide gameplay information unavailable to others','Supports local, online, and Infinity Taps'],evidence:'The store currently has trails, but the bible’s full character-particle component system is not implemented.'},
{id:'particles-catalog',section:'Character Particles',title:'Particle catalog and themed sets',pages:'29-40',status:'concept',summary:'Slime, stars, fire, leaves, petals, rainbows, black holes, bats, hearts, spores, runes, seasonal effects, and coordinated bundles.',requirements:['Individual effects generally range from 75 to 300 coins','Themed multi-component sets around 400 coins','Seasonal particles remain exclusive after their season','Character-specific items must clearly state compatibility'],evidence:'Design catalog only; current Sparks, Comet, and Bloom trails partially overlap the visual territory.'},
{id:'particles-tech',section:'Character Particles',title:'Particle anchors, preview, and performance',pages:'41-44',status:'pending',summary:'Marker-based attachment, live shop previews, strict particle budgets, and reduced remote-player versions.',requirements:['Back, center, head, feet, and tail anchors','Shop preview supports movement, jumps, landings, and effect combinations','Pooling, fixed lifetimes, emission caps, and off-screen reduction','Other Player Particles: Full, Reduced, or Off'],evidence:'Not present as a generalized system.'},
{id:'infinity-entry',section:'Infinity Taps',title:'Mode entry and current status',pages:'45-46',status:'partial',summary:'A noncompetitive local mode for fidgeting, relaxation, exploration, and permanent tap progress.',requirements:['No losing or ground-collision failure','No increasing gravity or survival pressure','No forced round restart','Offline play is a first-class requirement'],evidence:'The menu contains an INFINITY TAPS button and explicitly marks Solo Survival as parked, but the button is disabled and the actual mode is not built.'},
{id:'infinity-loop',section:'Infinity Taps',title:'Core tap, movement, and deformation loop',pages:'46-51',status:'pending',summary:'Every valid tap increases permanent progress and moves or deforms the character contextually.',requirements:['Resume from last saved location','Movement direction responds to tap location','Ground hopping, mountain climbing, swimming, floating, and low-gravity behaviors','World interactions can launch, carry, spin, or relocate the player','Validate events generously without punishing normal fast tapping'],evidence:'Specified in full; no InfinityTaps scene or manager exists.'},
{id:'infinity-rewards',section:'Infinity Taps',title:'Tap counter and Hero Coin rewards',pages:'49-51',status:'pending',summary:'Permanent lifetime and session counters with one Hero Coin per 1,000 eligible taps.',requirements:['Preserve remainder across sessions','Small nonintrusive reward notification','Counter survives offline play and later synchronization','Duplicate events and covered/paused input do not count'],evidence:'No Infinity-specific counter or reward ledger exists.'},
{id:'infinity-earth',section:'Infinity Taps',title:'Earth exploration and two-minute zones',pages:'52-56, 81',status:'pending',summary:'A continuous world of field, farmland, forest, mountains, desert, volcanic regions, polar regions, and layered oceans.',requirements:['Begin in a peaceful field','Horizontal distance, altitude, depth, biome, landmarks, and worlds are saved','Arctic and Antarctic are separate regions','Ocean progresses surface, sunlight, twilight, midnight, abyssal, and trench','Zones target roughly two minutes with arrival, interaction, discovery, and transition rhythm'],evidence:'No biome or world-travel implementation exists.'},
{id:'infinity-sky',section:'Infinity Taps',title:'Sky, space, and planets',pages:'57-58',status:'pending',summary:'Altitude progression from weather and aircraft through orbit, moons, planets, and exotic worlds.',requirements:['Sky encounters include birds, balloons, aircraft, storms, islands, and rare stars','Space includes satellites, stations, meteors, astronauts, alien ships, and signals','Every world has distinct palette, audio, creatures, landmarks, and movement behavior'],evidence:'Planned exploration content.'},
{id:'infinity-encounters',section:'Infinity Taps',title:'Encounters, rarity, and pity',pages:'59-60',status:'pending',summary:'Ambient, named, biome-exclusive, seasonal, secret, and legendary discoveries with anti-drought protection.',requirements:['Rare checks occur on meaningful intervals rather than every rendered event','Example: check every 100 taps with 0.1% base chance','Gradually increase chance after long droughts','Track last discovery and pity progress without exposing exact thresholds'],evidence:'No encounter manager or pity state exists.'},
{id:'infinity-journal',section:'Infinity Taps',title:'Discovery Journal and achievements',pages:'61-63',status:'pending',summary:'A permanent collection of biomes, worlds, characters, animals, landmarks, events, cosmetics, altitude, depth, and tap history.',requirements:['Show discovered and undiscovered collection structure','Include mode achievements such as Around the World and Fidget Session','Audio, haptics, wobble, particles, and environmental movement keep ordinary taps satisfying','Every sensory layer has independent controls'],evidence:'Current achievements do not include the full Infinity discovery collection.'},
{id:'infinity-tech',section:'Infinity Taps',title:'Managers, save model, and delivery phases',pages:'64-69',status:'pending',summary:'A dedicated scene and manager stack with staged delivery from tap feel through Earth, ocean, space, and expanded worlds.',requirements:['InfinityTapsManager, WorldTravelManager, BiomeManager, EncounterManager, DiscoveryManager, TapCounterManager, RewardManager','Atomic tap processing order and comprehensive save fields','Phase 1 proves tapping and movement before rewards','Never turn the mode into survival or punish inactivity'],evidence:'Bible provides an implementation plan; current project has none of the dedicated managers.'},
{id:'infinity-exclusive',section:'Infinity Exclusives',title:'Earned-only cosmetic identity',pages:'71-79',status:'pending',summary:'Some of the game’s most interesting cosmetics belong exclusively to calm exploration and can never be purchased.',requirements:['Not purchasable with coins, money, passes, bundles, or store offers','Unlock through taps, discoveries, encounters, secrets, altitude/depth, journal completion, or milestones','Permanent, account-wide, nontradable, and visibly sourced','Offline unlocks may queue for later validation','Server uses idempotent grant records'],evidence:'Current store supports reward-only items, which is a useful foundation, but Infinity acquisition records and rewards are not implemented.'},
{id:'economy-current',section:'Monetization',title:'Hero Coin economy and cosmetic store',pages:'83-97',status:'shipped',summary:'A cosmetic-only currency and catalog with server-authoritative purchases and reward-only items.',requirements:['No paid power, physics, fruit odds, or competitive advantages','Permanent product IDs and ownership records','Preview and clear source/rarity/ownership information are desired','Gameplay-earned, achievement, Infinity, and seasonal sources remain distinct'],evidence:'Catalog prices are shared between Godot and the Worker; purchases, ownership, equip state, bundles, and reward-only refusal are implemented.'},
{id:'economy-paid',section:'Monetization',title:'Paid packs, ad-free access, and supporter bundle',pages:'83-95',status:'pending',summary:'Proposed starter pack, coin packs, 30-day ad-free access, seasonal pass, and one-time founding supporter bundle.',requirements:['$0.99 starter pack is once per account','$2.99 ad-free entitlement lasts 30 days','$4.99 season pass has free and premium tracks','$9.99 supporter bundle includes permanent cosmetics and 60 ad-free days','No automatic renewal unless explicitly introduced'],evidence:'Backend contains IAP foundations, but the complete product lineup, entitlements, ads, and seasonal pass are not live.'},
{id:'economy-ads',section:'Monetization',title:'Advertising rules and purchase presentation',pages:'86-93',status:'pending',summary:'Ads stay outside live rounds; purchases are previewable, restorable, logged, and transparent.',requirements:['Never interrupt a live round','Use menu/post-round or optional reward placements','Effect preview supports repeated tapping and character movement','Validate receipts server-side and log every coin transaction','Restore purchases and retain earned seasonal cosmetics'],evidence:'Store/economy foundation exists; advertising and full purchase-preview experience do not.'},
{id:'brand-slogan',section:'Branding',title:'Official slogan and messaging',pages:'99-101',status:'partial',summary:'“Every Tap Against Me Takes You Further.” represents survival, exploration, progression, and discovery.',requirements:['Use subtly beneath the main logo and on store/marketing materials','Optional staged loading treatment','Compact-only variant: “Tap. Rise. Explore.”','Do not let the short variant replace the official slogan'],evidence:'The living-bible footer now uses the official slogan. Other current site and game surfaces still use older supporting copy and need alignment.'},
{id:'online-current',section:'Competitive Online',title:'Current online rooms and authoritative matches',pages:'104-105',status:'shipped',summary:'Account-backed public/private online play uses an authoritative shared simulation and server-validated results.',requirements:['Fast and fair match completion','Server owns economic and trusted result changes','Private matches remain available','Unranked play stays distinct from ranked progression'],evidence:'Lobby, room, network match, auth, validation, and leaderboards are present. This is the unranked foundation, not the full ranked scope.'},
{id:'rank-rating',section:'Competitive Online',title:'Glicko-2 rating and visible ladder',pages:'105-109',status:'pending',summary:'Hidden Glicko-2 skill paired with Bronze through Grandmaster visible progression.',requirements:['Bronze-Diamond each use divisions V through I','Master and Grandmaster use rating/leaderboard placement','Rank floors at major tiers','Visible stars or points separate from rating math','New and returning players carry higher rating uncertainty'],evidence:'Current code uses survival standings and leaderboards but has no Glicko-2 or seasonal rank profile.'},
{id:'rank-matchmaking',section:'Competitive Online',title:'Performance-aware matchmaking',pages:'109-112',status:'pending',summary:'Rating, recent survival, connection quality, and expanding queue windows work together to avoid absurd matches.',requirements:['Track average, median, recent 10/25, variance, recovery, item behavior, and disconnects','Treat survival bands as guidelines, not hard brackets','Expand rating, performance, and region over 5-15 seconds','Insert a suitable bot after roughly 15 seconds when allowed'],evidence:'Current lobby supports matches but not this ranked matchmaking model.'},
{id:'rank-bots',section:'Competitive Online',title:'Rated, human-like bots',pages:'112-119',status:'partial',summary:'Bots use the same rules, imperfect perception, randomized reactions, personalities, and rank-aware availability.',requirements:['No frame-perfect reactions, future spawn knowledge, or impossible physics','Beginner recognition 600-1000ms through Elite 100-280ms','Personalities: Floater, Aggressor, Climber, Technician, Trickster, Panicker','Bots reduce in higher ranks and disappear at Master/Grandmaster','Rotate profiles and reduce repeat rewards to prevent farming'],evidence:'Local bots and configurable bot difficulties exist. Rated profiles, reaction pipeline, personalities, ranked restrictions, and anti-farming are pending.'},
{id:'rank-seasons',section:'Competitive Online',title:'Placements, 90-day seasons, and rewards',pages:'119-123',status:'pending',summary:'Five placement matches, soft rating compression, permanent history, peak-rank rewards, and lower-tier win streaks.',requirements:['Soft reset concept: 1500 + ((old - 1500) × 0.60)','Increase deviation so new season skill adjusts quickly','Reward highest rank reached, not only final-day rank','Win streak bonus begins after three wins and stops at high tiers','Cosmetic rewards never grant power'],evidence:'No season records or rank reward track implemented.'},
{id:'rank-results',section:'Competitive Online',title:'Result processing, disconnects, and leaderboards',pages:'123-124',status:'partial',summary:'Server-side result validation, rating updates, abandonment handling, reconnection, history, and prestige boards.',requirements:['Fourteen-step result pipeline including validation, ratings, streaks, milestones, history, and boards','Reconnection grace and reason-aware disconnect handling','Queue penalties for repeated abandonment','Prestige boards prioritize verified human-vs-human results'],evidence:'Authoritative match results, connection handling, statistics, and general leaderboards exist. Ranked rating/streak/season processing is pending.'},
{id:'rank-data',section:'Competitive Online',title:'Ranked data model and remote configuration',pages:'125-127',status:'pending',summary:'Player rank, performance, match, bot, and season records with tuning controlled without client releases.',requirements:['Persist rating, deviation, volatility, tiers, peaks, streaks, placements, and split bot/human records','Store full validated match before/after ratings and connection data','Remote-tune thresholds, queue expansion, bots, resets, rewards, and grace periods'],evidence:'Existing D1 schema covers accounts, economy, and matches but not the bible’s ranked profile set.'},
{id:'rank-mvp',section:'Competitive Online',title:'Ranked MVP acceptance scope',pages:'128-130',status:'pending',summary:'A testable first competitive release with ratings, tiers, placements, expanding matchmaking, bot backfill, seasons, and validation.',requirements:['Two real players complete a ranked match and update correctly','A 15-second player is not normally matched with a 72-second player','Bots respond with randomized delays and make credible mistakes','Progress resets after 90 days while history remains','All rating and result authority stays server-side'],evidence:'This remains the clearest definition of done for ranked mode.'},
{id:'vision-product',section:'Vision & Audience',title:'Two pillars, one expandable universe',pages:'Executive Vision; Product Architecture',sourceId:'tam_game_bible',status:'partial',summary:'TAM joins a mastery-focused competitive survival game with a no-failure exploration/fidget experience, sharing characters, identity, progression, and technology.',requirements:['Every session should produce visible progress','Competition and relaxation are equal first-class relationships with the game','Quick-session players, ranked players, fidget players, collectors, and pixel-art fans are all explicit audiences','Grow through modular, data-driven content rather than repeated system rewrites'],evidence:'Competitive survival, accounts, progression, and shared cosmetic identity exist. The Infinity pillar and recurring live universe remain pending.'},
{id:'vision-pillars',section:'Vision & Audience',title:'Four product pillars and session expectations',pages:'Sections 3-5',sourceId:'tam_game_bible',status:'partial',summary:'Accessible one-tap mastery, fair competition, pressure-free exploration, and expressive collection define the product.',requirements:['Begin meaningful play within seconds','Support short survival attempts and open-ended Infinity sessions','Do not fragment launch population with undefined public queues','Solo Survival remains a complete offline mode, not a lesser multiplayer substitute'],evidence:'The core and solo/online foundation support several pillars; Infinity exploration and mature expressive systems do not.'},
{id:'brand-meaning',section:'Branding',title:'Name meaning, tone, and visual anchors',pages:'Section 2',sourceId:'tam_game_bible',status:'partial',summary:'“Me” is deliberately ambiguous: the game, gravity, an opponent, the world, or the player’s previous self.',requirements:['Playful, energetic, mischievous, and expressive rather than hostile or militaristic','Infinity feels curious, gentle, strange, and rewarding','Retro pixel art, portrait mobile composition, purple accents, readable silhouettes, expressive deformation','Tap feedback must be immediate and visually satisfying'],evidence:'The game and website use the pixel-art/purple identity. Full tone consistency, deformation, and contextual feedback require continuing art and UX work.'},
{id:'core-difficulty',section:'Core Game Feel',title:'Staged difficulty and skill expression',pages:'TAM Game Bible 4.3-4.5',sourceId:'tam_game_bible',status:'partial',summary:'Rising gravity preserves the simple rule while timing, positioning, recovery, restraint, and pickup risk create mastery.',requirements:['Escalate in perceptible stages, not only an invisible linear value','Telegraph stages through audio, background motion, particles, framing, or item weighting','Strong play should look calm and intentional, not like maximum-rate tapping','Support close calls with readable sound, stretch, subtle camera response, and no pause'],evidence:'Gravity scaling, survival tracking, close-call statistics, and achievements exist. Full audiovisual stage telegraphing and close-call presentation remain incomplete.'},
{id:'pickup-rules',section:'Core Game Feel',title:'Pickup effects, reaction timing, and spawn fairness',pages:'TAM Game Bible Section 6; Game Bible v1 Sections 10 and 14',sourceId:'game_bible_v1',status:'partial',summary:'Apples, poison, and tokens create readable risk without hidden snapping, ambiguous collection, or unfair spawn geometry.',requirements:['Apple boost should be temporary and bounded; exact stacking remains tuning','Poison is dangerous but survivable, with visible status feedback','Tokens deliberately lure players away from safe lines','Bots perceive, evaluate, hesitate, and sometimes miss before pursuing items','Ranked servers can reconstruct or validate spawns'],evidence:'All three pickup types and related achievements exist. The newest bibles still mark timing, bounded boosts, status presentation, and ranked spawn validation as tuning or pending.'},
{id:'living-world',section:'Living World',title:'Layered environmental reaction standard',pages:'TAM Game Bible Sections 9-10; Game Bible v1 Sections 25-29',sourceId:'game_bible_v1',status:'pending',summary:'Anything that looks tappable should respond, while repeated taps reveal escalations, alternatives, chains, secrets, and context-sensitive behaviors.',requirements:['Objects support thresholds, cooldowns, random variants, context conditions, and secret combinations','Animals and creatures have discoverable behavior sets rather than one canned animation','Hero sightings may be ambience, humor, lore, discovery, or commerce—but not constant sales prompts','Biomes define movement, wildlife, palette, sound, music, secrets, encounters, boosts, and rewards'],evidence:'This is a new broader world-content standard. The current game has core arena backgrounds and pickups, not a generalized interaction graph.'},
{id:'biome-launch-set',section:'Living World',title:'Proposed eight-biome early content set',pages:'Game Bible v1 Section 29',sourceId:'game_bible_v1',status:'concept',summary:'Meadow, Forest, Snow, Beach, Crystal Caverns, Neon City, Mushroom Grove, and Space form a proposed early Infinity content set.',requirements:['The set is a recommendation, not permission to build all eight before the core loop is stable','Typical zones target two minutes but never enforce a timer','Transitions should feel spatial and musical','Every biome needs its own interaction and reward vocabulary'],evidence:'The existing background most closely supports a meadow/field visual seed. No traversable biome set exists.'},
{id:'heroes-art',section:'Characters & Art',title:'Hero role, Velvet Hex, and animation minimums',pages:'TAM Game Bible Section 11; Game Bible v1 Section 34',sourceId:'tam_game_bible',status:'partial',summary:'Heroes are readable personalities, collectible identities, world inhabitants, and cosmetic anchors—not alternate physics classes.',requirements:['Competitive silhouettes and collision behavior remain equivalent','Velvet Hex anchors purple, feline/slime ambiguity, expressive eyes, squash-and-stretch, and mischievous tone','Variants must remain recognizable as the same hero','Minimum states cover idle, rise, fall, land/eliminate, pickup, and special reactions'],evidence:'Velvet Hex and a substantial sprite-sheet variant roster are implemented. The fuller animation/reaction minimum and natural world encounters are incomplete.'},
{id:'audio-identity',section:'Audio & Haptics',title:'Musical identity and contextual arrangements',pages:'TAM Game Bible Section 15; Game Bible v1 Sections 48-54',sourceId:'game_bible_v1',status:'pending',summary:'A recognizable TAM musical theme adapts across menu, survival intensity, ranked tension, and Infinity biomes.',requirements:['Core palette favors retro synths, chiptune colors, playful percussion, melodic bass, and expressive motifs','Gravity stages may add intensity without masking input feedback','Two-minute Infinity zones should expose most of an arrangement','Biome transitions preserve motif while changing instrumentation','Compress and loop assets for mobile delivery'],evidence:'No mature contextual music or adaptive audio system is visible in the current repository.'},
{id:'reactive-audio',section:'Audio & Haptics',title:'Reactive sound and comfort controls',pages:'TAM Game Bible 15.4-15.6',sourceId:'tam_game_bible',status:'pending',summary:'Taps, close calls, pickups, rare discoveries, world reactions, and temporary boosts have clear but non-fatiguing sonic and haptic identities.',requirements:['Fast tapping must not create painful additive sound','Independent controls for music, effects, cosmetic audio, and haptics','Haptics remain optional and restrained','Rare discoveries can temporarily reshape the musical layer'],evidence:'Audio and haptic settings are not yet a complete player-facing system.'},
{id:'ui-mobile',section:'UI & Accessibility',title:'Mobile-first shell, HUD, and navigation',pages:'TAM Game Bible Section 16; Game Bible v1 Sections 55-57',sourceId:'game_bible_v1',status:'partial',summary:'Portrait mobile presentation prioritizes large touch targets, immediate mode access, a readable playfield, and low-friction retry/rematch.',requirements:['Normalize mouse and touch through the same tap action','Keep survival time visible without covering the arena','Use compact opponent portraits, altitude, or elimination markers when full remote rendering hurts clarity','Results show outcome, time, records, progress, rewards, and immediate next action'],evidence:'The Godot shell is explicitly mobile-first and includes main screens and results logic. Final HUD clarity and richer results/progress presentation need polish.'},
{id:'accessibility-full',section:'UI & Accessibility',title:'Complete accessibility and comfort matrix',pages:'TAM Game Bible 16.5; Game Bible v1 Section 58',sourceId:'game_bible_v1',status:'pending',summary:'Visual, audio, motion, haptic, and multiplayer cosmetic intensity can be tailored without sacrificing core information.',requirements:['Particle density, opacity, screen shake, flashes, lightning, cosmetic audio, and haptics','Other-player effects and particles: Full, Reduced, or Off','High-contrast readable states that do not rely on color alone','Comfortable rapid-input audio and no forced full-screen flashes'],evidence:'Individual design rules exist, but a consolidated settings surface is not implemented.'},
{id:'client-architecture',section:'Technology',title:'Godot client and data-driven manager architecture',pages:'TAM Game Bible Section 17; Game Bible v1 Sections 60 and 68',sourceId:'tam_game_bible',status:'partial',summary:'Godot 4 separates simulation, presentation, persistence, content catalogs, and services so new content is primarily data.',requirements:['Normalized inputs and shared versioned simulation constants','Autoloads/managers own saves, accounts, catalog, achievements, challenges, analytics, and networking','Cosmetics, achievements, challenges, encounters, and biomes use stable IDs and definitions','Avoid hard-coding balance values across unrelated scripts'],evidence:'The current project already has service-style scripts, shared catalogs, tunable configuration, and shared server simulation. Infinity and content systems still need their specified managers.'},
{id:'backend-architecture',section:'Technology',title:'Authoritative backend, identity, and synchronization',pages:'TAM Game Bible 17.4-17.8; Game Bible v1 Sections 61-65',sourceId:'game_bible_v1',status:'partial',summary:'Accounts and trusted state live behind authoritative Workers/Durable Objects/D1 while offline-safe progress merges deliberately.',requirements:['Support guest play, email/account flow, Google sign-in direction, and username identity','Server owns match results, coins, purchases, ratings, and trusted achievements','Use sequence IDs, timestamps, duplicate suppression, replay protection, and idempotent grants','Cross-device merge policies must avoid duplicate currency and blind last-write-wins loss'],evidence:'Cloudflare Worker, Durable Objects, D1 migrations, auth, rooms, economy, sync, and validation are substantial shipped foundations. Some Google, merge, IAP, and ranked concerns remain.'},
{id:'security-integrity',section:'Security & Analytics',title:'Anti-cheat and economic integrity',pages:'TAM Game Bible Section 18; Game Bible v1 Sections 19 and 66',sourceId:'game_bible_v1',status:'partial',summary:'TAM permits real fast tapping but rejects impossible sustained input, forged state, replayed messages, and client-authored rewards.',requirements:['Rate and burst analysis distinguishes skill from automation','Flag suspicious matches for review rather than relying only on instant punishment','Clients cannot author currency, ownership, rank, wins, or final survival','Version shared simulation and make match/reward submission idempotent','Respect privacy and collect only purposeful data'],evidence:'Validation, authoritative rooms, economy checks, duplicate protection, and security documentation exist. Ranked review tooling and mature anomaly operations remain pending.'},
{id:'analytics-targets',section:'Security & Analytics',title:'Analytics goals and early product targets',pages:'TAM Game Bible 18.1-18.2; Game Bible v1 Section 67',sourceId:'tam_game_bible',status:'partial',summary:'Telemetry should answer whether players understand tapping, return, reach meaningful survival, engage with Infinity, and value fair cosmetics.',requirements:['Measure onboarding completion, session length, survival distributions, retries, mode use, challenge completion, and store conversion','Track Infinity tap sessions, zone progression, discoveries, and reward droughts','Use event names and stable properties rather than unstructured logging','Do not collect sensitive data without product need'],evidence:'An analytics service exists, but complete event coverage and product dashboards are not evidenced.'},
{id:'performance-budgets',section:'Technology',title:'Mobile performance and content budgets',pages:'Game Bible v1 Section 69; TAM Game Bible effect sections',sourceId:'game_bible_v1',status:'partial',summary:'Rapid taps, particles, networking, and long Infinity sessions must remain stable on mobile through explicit budgets and degradation paths.',requirements:['Cap particles, active effects, accumulation zones, temporary creatures, decals, and audio voices','Pool repeated objects and limit off-screen work','Provide reduced CPU particle or simplified fallbacks','Test memory stability during long sessions and scene/biome transitions','Remote players receive cheaper visual representations'],evidence:'Current art is lightweight pixel content and the code includes some pragmatic limits. The full cross-system budget and quality-level framework is pending.'},
{id:'ghost-opponents',section:'Competitive Online',title:'Verified ghost opponents',pages:'Game Bible v1 Section 17',sourceId:'game_bible_v1',status:'concept',summary:'Recorded authoritative runs can support asynchronous races, personal-best training, daily challenges, and friend comparisons without pretending to be live.',requirements:['Clearly label every ghost as recorded performance','Build from verified input or authoritative state','Version physics and arena rules','Do not affect live Glicko unless a separate asynchronous ladder is designed','Support personal ghost replay'],evidence:'Proposed future feature; no replay or ghost data system exists.'},
{id:'roadmap-current',section:'Roadmap & Decisions',title:'Reconciled release sequence',pages:'TAM Game Bible Section 19; Game Bible v1 Sections 70-76',sourceId:'tam_game_bible',status:'partial',summary:'Stabilize core feel and online/account foundations, prove Infinity with a narrow vertical slice, deepen progression/economy, then expand ranked, seasons, and the Infinity universe.',requirements:['Do not let breadth outrun one excellent core loop','Each phase has explicit acceptance outcomes','Build one reactive Infinity zone before a large biome catalog','Keep future systems modular and data-driven','Treat public ranked and live operations as later trust-sensitive milestones'],evidence:'The repository has progressed through much of the foundation/account/online/progression work. Infinity vertical slice is the clearest missing early milestone.'},
{id:'decision-language',section:'Roadmap & Decisions',title:'Decision status and conflict rules',pages:'Document Control; Game Bible v1 Decision Language',sourceId:'game_bible_v1',status:'partial',summary:'LOCKED and CONFIRMED statements outrank PROPOSED, TUNING, and OPEN material; newer explicit decisions override older conflicts.',requirements:['Preserve source labels instead of presenting every idea as committed','LOCKED: core identity or non-negotiable boundary','CONFIRMED: approved direction','PROPOSED: strong candidate awaiting approval','TUNING: direction exists, exact values need testing','OPEN: unresolved product decision'],evidence:'The new Source Library preserves documents separately. The Living Bible uses implementation status, which complements rather than replaces design decision status.'},
{id:'open-decisions',section:'Roadmap & Decisions',title:'Open questions requiring formal specification',pages:'TAM Game Bible Section 20; Game Bible v1 Section 79',sourceId:'game_bible_v1',status:'concept',summary:'Several exact values and policies must remain visibly unresolved until playtesting or a signed-off specification decides them.',requirements:['Apple duration and stacking','Final public match size and queue structure','Rank division count for real population','Bot disclosure/policy by mode and rank','Infinity launch biome count and reward cadence','Cross-device offline merge and pending-currency validation','Ad cadence, season reward structure, and long-session performance targets'],evidence:'These must not be silently converted into shipped facts. The tracker keeps them pending or concept-stage until explicit decisions and implementation evidence exist.'},
{id:'two-title-architecture',section:'Product Architecture',title:'Separate player-facing games, shared TAM ecosystem',pages:'Sections 1-3',sourceId:'tam_game_design_full',status:'partial',summary:'The newest explicit direction supersedes the older single-app framing: Competitive TAM and Infinity Taps should publish as separate player-facing games while sharing practical infrastructure.',requirements:['Competitive product retains the primary Tap Against Me name','Infinity naming remains open; “A Tap Against Me Adventure” is only a possible subtitle','Share account, catalog, eligible ownership, characters, cosmetics, music motifs, achievements, and backend infrastructure','Keep rank/season state separate from Infinity biome, journal, and discovery state','Technical reuse should feel like continuity, not a stitched-together launcher'],evidence:'The current repository provides strong shared account, catalog, economy, and backend foundations, but it is still one client with a disabled Infinity menu entry rather than two player-facing products.'},
{id:'shared-account-boundary',section:'Product Architecture',title:'Cross-title ownership and source-aware progress',pages:'Sections 3.3-3.4 and 22.5',sourceId:'tam_game_design_full',status:'partial',summary:'A player owns a shared hero once, while product-specific accomplishments remain auditable and cannot leak into the wrong progression system.',requirements:['Store explicit product source and ruleset version on achievement events and grants','Infinity-exclusive items may be wearable in Competitive after being earned, but never purchased there','Competitive rating belongs only to Competitive TAM','Biome, zone, discovery, and journal progress belong only to Infinity','Resolve whether Hero Coin is one wallet or has title-specific earning caps'],evidence:'Stable catalog IDs and account ownership exist. Product-source fields and cross-title save boundaries are not implemented.'},
{id:'alternate-match-rules',section:'Competitive Online',title:'Alternate competitive rule families',pages:'Section 9',sourceId:'tam_game_design_full',status:'concept',summary:'Survival remains primary; Most Taps, First to Zero, Dual Victory, tournaments, and free-for-all are reserved candidates after 1v1 reliability and population are proven.',requirements:['Most Taps must reward meaningful movement skill and resist macro farming','First to Zero damage/regeneration remains undefined and can never become purchasable power','Dual Victory works better as a bonus or event rule than a confusing standard win condition','Do not fragment the launch population with premature queues','Results should expose winner, time, valid taps, pickups, rating change, progress, and rewards'],evidence:'The shipped simulation is survival-focused. Alternate rule families are not implemented and must not appear as committed launch modes.'},
{id:'bot-disclosure',section:'Competitive Online',title:'Explicit AI, CPU, and ghost disclosure',pages:'Sections 11 and 28',sourceId:'tam_game_design_full',status:'partial',summary:'Bots can protect queue health, but the game must not impersonate humans or manufacture a fake population.',requirements:['Identify AI/CPU opponents clearly where they appear','Ghosts must be labeled as recorded performance','Bots use the same rules, physics, tap limits, and information boundaries','No hidden bot impersonation is a non-negotiable safeguard','Explain restrictions or withheld rating when enforcement affects a result'],evidence:'Bots already exist as actual game participants. The complete disclosure language, rated bot profiles, and ghost presentation are pending.'},
{id:'infinity-concrete-mvp',section:'Infinity Taps',title:'One-biome Infinity vertical-slice acceptance test',pages:'Section 13.5 and Appendix D.3',sourceId:'tam_game_design_full',status:'pending',summary:'The first Infinity proof is a small zen playground, judged by reaction depth rather than biome count.',requirements:['No input or environmental event can create a loss screen','Reactive water, a wiggling bush, falling tree leaves, and repeated-tap variants','At least one animal with three interaction stages','One found hero or variant with in-world identity and acquisition path','Persistent lifetime taps and exactly one coin at 1,000 valid taps','One earned-only reward absent from every direct-purchase catalog','Biome music loops or transitions cleanly with varied environmental sound'],evidence:'The menu placeholder exists, but none of this vertical-slice acceptance scope is implemented.'},
{id:'hero-encounter-flow',section:'Characters & Art',title:'In-world hero discovery and acquisition flow',pages:'Section 16',sourceId:'tam_game_design_full',status:'pending',summary:'A hero encounter must feel like a discovery before it becomes a transaction.',requirements:['First show an in-world reaction','Then show a compact card with hero, variant, rarity, ownership, and acquisition method','Require a second deliberate action for the full purchase/unlock view','Return to the same encounter state after closing','Owned heroes can acknowledge, accompany, reveal lore, or build encounter history','Base-hero ownership never implies ownership of a discovered variant'],evidence:'The catalog distinguishes exact skin IDs and ownership. No Infinity encounter or layered acquisition UI exists.'},
{id:'social-moderation',section:'Security & Analytics',title:'Conservative social and moderation scope',pages:'Section 23.4',sourceId:'tam_game_design_full',status:'pending',summary:'TAM should gain social identity without creating unnecessary chat and moderation risk.',requirements:['Filter and report display names, profile text, and emotes','Direct chat is not necessary for the core product','Prefer friend invites and preset emotes for lower-risk connection','Provide proportionate enforcement and appeals for severe actions','Privacy controls cover recent matches, detailed statistics, and social discovery'],evidence:'Username identity and private play exist. Reporting, moderation workflows, preset-emote scope, and profile privacy controls are not complete.'},
{id:'battery-data',section:'Technology',title:'Long-session battery and data quality',pages:'Section 25.6',sourceId:'tam_game_design_full',status:'pending',summary:'Infinity may remain open as a fidget companion for long sessions, so efficiency is a product feature rather than an afterthought.',requirements:['Low-power mode and frame-rate caps','Reduced ambience and environmental population options','Predictable network/data use','Consider optional downloadable biome music or asset packs later','The base experience must remain complete without optional downloads'],evidence:'No explicit low-power settings or Infinity long-session performance mode exists.'},
{id:'audio-package-budget',section:'Audio & Haptics',title:'Eight-track shipping and compression gate',pages:'Sections 20.7 and Appendix D.5',sourceId:'tam_game_design_full',status:'pending',summary:'The discussed eight-track set is roughly 27 MB and should be reduced toward a 10-15 MB mobile target without obvious artifacts.',requirements:['Keep lossless masters outside the shipping asset set','Ship agreed Opus or Vorbis compression','Stream long tracks rather than loading them fully','Test loop points on target Android hardware','Verify that compression and streaming do not introduce load spikes'],evidence:'The repository does not show the specified eight-track compressed streaming package.'},
{id:'android-two-device-gate',section:'Technology',title:'Physical Android and two-device private-match gate',pages:'Addendum pp. 29-31 and 35-37; Appendix D.2',sourceId:'game_design_addendum',status:'partial',summary:'A connected editor test is not sufficient: the milestone requires two separate physical Android phones, accounts, and one authoritative production match.',requirements:['Install and configure Godot export templates, Android SDK, and OpenJDK','Use a runnable package preset and one-click deploy','Two phones sign in as different users and enter the same authoritative match','Both clients and server agree on ground contact and winner','Result and reward write exactly once','Exercise reconnect, timeout, duplicate submission, version mismatch, and rematch paths'],evidence:'Android export configuration, accounts, authoritative rooms, and duplicate protections exist. A completed documented production test across two physical phones is not evidenced.'},
{id:'release-integrity-gates',section:'Roadmap & Decisions',title:'Ranked and Infinity release gates',pages:'Sections 26.5 and 28',sourceId:'tam_game_design_full',status:'pending',summary:'Connectivity and content volume are not release criteria by themselves; each product has a trust and quality gate.',requirements:['Do not launch ranked without physics versioning, credible matchmaking, explainable results, disconnect policy, reward integrity, and bot disclosure','Do not launch Infinity with many empty biomes','One deeply reactive biome is better than ten decorative backgrounds','No effect may obscure ground or collision state','No biome expansion may outrun interaction depth'],evidence:'The current roadmap now reflects these gates. Both release criteria remain unmet.'},
{id:'content-reuse-quality',section:'Living World',title:'Content reuse and response-depth quality bar',pages:'Section 27',sourceId:'tam_game_design_full',status:'concept',summary:'Shared assets gain value through title-specific behavior, while quality is measured by response depth, readability, personality, and acquisition clarity.',requirements:['A ranked hero can later receive Infinity encounter behavior','A shop tap effect can gain biome-specific reactions','A shared musical motif can be rearranged by product and biome','Seasonal ownership remains unambiguous even when unlock paths differ','A rabbit with seven behaviors is more valuable than a new animal with one loop'],evidence:'Shared character art, cosmetics, and catalogs create a reuse foundation. The behavior/content pipeline is not built.'},
{id:'canonical-workshop',section:'Roadmap & Decisions',title:'Next decision-lock workshop',pages:'Section 29.3',sourceId:'tam_game_design_full',status:'pending',summary:'Four decision groups unlock the most engineering and content progress without pretending every future feature is already specified.',requirements:['Lock competitive physics values','Lock two-device private-match acceptance criteria','Lock shared-account and product-source boundaries','Lock the one-biome Infinity vertical slice','Leave later biomes, heroes, and seasons modular until evidence justifies them'],evidence:'The website now makes these four decision areas visible, but their final approved specifications still need explicit sign-off.'},
{id:'day-night-decoupling',section:'Competitive Presentation',title:'Decouple gravity from environmental darkness',pages:'pp. 1-5, 13-15, 28-29',sourceId:'competitive_day_night',status:'partial',summary:'Approved direction: gravity communicates mechanical pressure through physics and impact, while day/night communicates time, atmosphere, and world continuity. Neither system controls the other.',requirements:['Gravity must not directly darken the sky','Time of day must not change gravity, spawns, movement, scoring, input, or bot behavior','Purple Fruit affects only the collected player and never the global sky','Both systems may read authoritative elapsed time but evaluate independent profiles','UI remains visually stable and outside world lighting'],evidence:'Current offline main.gd and online_match.gd still tint sky/background layers from effective gravity. The existing implementation must be audited and decoupled without changing gameplay gravity.'},
{id:'day-night-cycle',section:'Competitive Presentation',title:'Locked 120-second continuous competitive cycle',pages:'pp. 3, 6-9',sourceId:'competitive_day_night',status:'pending',summary:'A full accelerated day passes every 120 seconds, creating endurance context and match-to-match atmosphere without becoming a gameplay timer.',requirements:['Sunrise 0-12s; morning/day 12-42s; afternoon/sunset 42-60s','Twilight 60-72s; night 72-108s; predawn 108-120s','Interpolate every phase; never swap four static backgrounds','Sun and moon visibly traverse portrait-safe arcs','Wrap at 120 seconds with no flash, palette reset, teleport, or lighting discontinuity','Initial validation may always start at sunrise'],evidence:'The current game uses a static sky texture and gravity-derived tint; there is no independent normalized cycle.'},
{id:'day-night-anchors',section:'Competitive Presentation',title:'Authoritative curated starting phases',pages:'pp. 8-10, 18-20',sourceId:'competitive_day_night',status:'pending',summary:'After fixed-sunrise validation, the match seed selects recognizable starting anchors so short matches expose more of the complete cycle.',requirements:['Anchors: sunrise 0.00, midday 0.25, sunset 0.45, early night 0.62, midnight 0.75, predawn 0.92','Both players, bots, replays, and spectators use the same environment seed and start phase','Curated anchors are preferred over uncontrolled randomness','Starting phase remains competitively neutral','Pre-match countdown generally holds the phase still'],evidence:'Authoritative match configuration exists, but it does not carry environment profile, seed, cycle duration, starting phase, or environment variant.'},
{id:'day-night-readability',section:'Competitive Presentation',title:'Protected readability through every sky phase',pages:'pp. 3-4, 7, 11-13, 27, 35-38',sourceId:'competitive_day_night',status:'pending',summary:'Night can be atmospheric and sunset can be rich, but no cosmetic phase may change the ability to identify a player, pickup, hazard, or interface state.',requirements:['Minimum character brightness, outline, rim light, and background separation','Protect pickup emissive range and dim/suppress background immediately behind critical objects when necessary','Golden Hero Tokens remain distinct during sunset','Green Apples remain distinct from foliage; Purple Fruits remain distinct at twilight/night','Never let paid skins glow more clearly than ordinary characters in ranked','Test shape, icon, outline, animation, contrast, and color against common color-vision deficiencies'],evidence:'The current art remains readable in its single palette, but there is no multi-phase readability controller, night-visibility setting, or full object/skin test matrix.'},
{id:'gravity-presentation',section:'Competitive Presentation',title:'Physical and audio language for gravity strength',pages:'pp. 14-18, 32-33',sourceId:'competitive_day_night',status:'partial',summary:'Players should feel increasing gravity through movement, mass, pressure, animation, particles, meter behavior, and sound rather than darkness.',requirements:['Faster descent, downward particle drift, heavier squash, forceful recovery, wind streaks, environmental sway, and impact anticipation','Use subtle camera impulse only at meaningful thresholds','Low gravity uses hang time, floating accessories, soft impacts, reduced squash, and wider arcs','Purple Fruit gets a distinct pulse, downward streak, icon/timer, low-frequency cue, and player-local feedback','All signals remain subordinate to input and position clarity'],evidence:'Gravity physics and faster parallax already provide some physical pressure. The richer presentation controller and distinct Purple Fruit feedback are incomplete; sky tint must be removed.'},
{id:'environment-sync',section:'Competitive Presentation',title:'Seeded environment synchronization and drift correction',pages:'pp. 18-21, 31, 34',sourceId:'competitive_day_night',status:'pending',summary:'Clients derive the same environment locally from authoritative match time instead of receiving colors every frame.',requirements:['Match data: environment seed, profile, 120s duration, start phase/time, biome, and environment variant','Phase = (starting phase + elapsed / cycle duration) modulo 1','Ignore drift under 50ms; smooth 50-250ms; accelerate over 250ms; restore after reconnect with a short blend','Deterministically reproduce clouds, stars, animals, and distant events where needed','Replays and spectators reconstruct the same cycle timeline','Environmental synchronization must not increase gameplay latency'],evidence:'The authoritative network clock and room model provide a foundation, but environment configuration, reconstruction, drift handling, and replay fields are not implemented.'},
{id:'environment-architecture',section:'Technology',title:'Modular competitive environment controllers',pages:'pp. 21-25',sourceId:'competitive_day_night',status:'pending',summary:'Time ownership, biome interpretation, celestial movement, readability, gravity feedback, reactions, and ambience remain separate modules.',requirements:['MatchEnvironmentController owns phase and synchronization but never gravity','DayNightProfile stores gradients, curves, celestial arcs, ambience, and fallbacks','SkyRenderer and CelestialController render only background atmosphere','GameplayReadabilityController protects players and pickups without changing collision','GravityPresentationController reads effective gravity but never sky phase','BiomeReactionController and EnvironmentalAudioController schedule cosmetic responses'],evidence:'Current background presentation lives directly in match scripts and is tightly coupled to player gravity. The proposed resource/controller split does not exist.'},
{id:'environment-quality',section:'Competitive Presentation',title:'Performance tiers and sensory accessibility',pages:'pp. 25-28, 33-35',sourceId:'competitive_day_night',status:'pending',summary:'High, medium, and low visual tiers preserve the same competitive information and cycle identity across Android hardware.',requirements:['High may use glow, directional shadows, reflections, particles, and full ambience','Medium reduces stars, shadows, particles, and reflections','Low retains gradient, sun/moon motion, minimal stars, and protected readability','Reduced motion removes impulses, streaks, animal motion, and parallax while colors may continue','Reduced effects trims glow, reflections, fireflies, fog, and shadow animation','Validate 30/60 FPS, thermal throttling, battery saver, maximum cosmetics, repeated restarts, and full loops'],evidence:'No independent environment quality tiers or dedicated sensory settings exist.'},
{id:'environment-biomes-audio',section:'Competitive Presentation',title:'Restrained biome reactions and independent ambience',pages:'pp. 15-18, 32',sourceId:'competitive_day_night',status:'pending',summary:'Competitive biomes can react to time of day, but remain quieter than Infinity and never demand primary attention.',requirements:['Every biome defines day/sunset/night/sunrise palettes, sun/moon, stars, contrast, ambience, and fallback','Cosmetic reactions may include flowers, fireflies, owls, bats, moths, lights, reflections, mist, crickets, and birds','Priority order: player, opponent, hazards, pickups, match information, then spectacle','Ambient layers crossfade beneath uninterrupted competitive music','Ambience must not mask taps, pickups, debuffs, match cues, results, or network warnings'],evidence:'Current competitive background has layered art and parallax but no biome profile, day/night reactions, or environmental audio mixing.'},
{id:'environment-release-gate',section:'Roadmap & Decisions',title:'Eight-phase day/night production gate',pages:'pp. 28-39',sourceId:'competitive_day_night',status:'pending',summary:'The feature proceeds from audit and decoupling through a minimal cycle, readability, synchronization, variety, reactions, gravity refinement, and release QA.',requirements:['Phase 0 finds and removes every gravity-to-darkness relationship','MVP proves one seamless 120-second loop on target Android','Art phase validates every pickup, skin, effect, warning, and UI element in six time ranges','Two physical devices stay synchronized without per-frame environment state','Analytics tests loss rates, exits, frame drops, pickup rates, drift, and accessibility outcomes by phase','Production requires no gameplay regression, visibility advantage, loop discontinuity, load hitch, or frame instability'],evidence:'Phase 0 has a known starting point in main.gd and online_match.gd. No implementation phase is complete.'},
{id:'competitive-biome-expansion',section:'Competitive Presentation',title:'Five-biome competitive arena expansion',pages:'Feature Bible v1.0, pp. 1-38',sourceId:'competitive_biomes_v1',sourceFile:'Tap_Against_Me_Competitive_Biome_Expansion_Feature_Bible_v1.0.pdf',sourceTitle:'Competitive Biome Expansion Feature Bible v1.0',status:'pending',summary:'Build Desert, Snowy Mountain, Wheat Field, Ocean, and Luminescent Mushroom Forest as visually distinct but competitively neutral arenas on one reusable scene, fixed geometry, synchronized cosmetic clock, and protected-readability contract.',requirements:['Support head-to-head, public, ranked, private, bot-supported, and appropriate solo competitive matches without biome-specific advantage','Keep player physics, tap force, gravity, spawn rules, pickup behavior, camera framing, arena dimensions, collision, and results identical across standard biomes','Use the shared order: far sky, far background, midground, gameplay, lose surface, foreground, atmosphere, then HUD and reactions','Keep foreground decoration at edges or below play so it cannot hide a player during normal movement','Keep one fixed lose-surface collision height even when sand, snow, wheat, water, or fungal moss visually moves around it','Drive every biome from the independent continuous 120-second day-and-night cycle with biome-specific dawn, day, sunset, night, sun, moon, ambient light, emissive accents, and minimum visibility','Implement a reusable CompetitiveBiome scene and resource with sky, parallax, boundary, ambient, creature, lighting, audio, animation, palette, wind, ground, effect, and loss fields','Desert uses layered dunes, restrained cacti, low sand drift, 8-18 second wind pulses, slow clouds, optional lower-screen heat haze, and a nonblocking sand-puff loss','Snowy Mountain uses parallax peaks, fog, pines, multi-depth snowfall, 10-22 second wind pulses, rare background snow shedding, and a powder loss without blizzard density','Wheat Field uses layered phase-offset stalks, readable soil, 5-12 second wind-streak groups, 15-30 second gusts, distant birds, and a visible chaff-and-bending loss','Ocean uses layered waves and foam around a fixed highlighted waterline; visual peaks never move collision or hide the distance to loss','Build DolphinEvent as a reusable behind-play scene with bidirectional and paired variants, curved arcs, rotation, entry and exit splashes, ripples, tint, audio, and approximately 18-45 second cosmetic timing','Luminescent Mushroom Forest uses canopy silhouettes, glowing fungi, pulsing emissive accents, slow spores, edge-biased foreground, and a bright readable fungal floor','Build MushroomGremlin as a reusable hidden, peeking, watching, running, surprised, and exiting state machine using cover markers and predefined behind-play paths only','Major creature events use the shared cosmetic seed and authoritative biome time; harmless micro-particles may differ and cosmetic desync degrades gracefully','Ambient animation never obscures players, resembles pickups or hazards, covers central play, produces high-frequency flashing, changes physics, or adds random ranked obstacles','High, Standard, and Performance tiers preserve core silhouettes, sky identity, essential ambience, loss-boundary clarity, and identical competitive information','Inventory shared and biome-specific sky, scenery, ground, particles, creature, loss, audio, controller, and configuration assets before production','Validate fixed collision, visibility across skins and time phases, no HUD obstruction, deterministic major events, no authoritative loss delay, 30/60 FPS targets, reconnects, replays, and reduced-effects modes'],evidence:'Planned. Existing layered backgrounds, biome assets, parallax code, and day-night design work provide useful foundations, but the evidence does not yet prove one reusable CompetitiveBiome scene, five release-complete arenas, the fixed cross-biome boundary contract, synchronized cosmetic events, DolphinEvent, MushroomGremlin, full quality tiers, or the complete acceptance matrix.',sourceExcerpt:'Five competitive biomes provide visual identity without competitive advantage. Every arena retains standardized geometry, physics, spawns, pickup behavior, framing, and one fixed loss boundary while using a shared reusable scene and independent 120-second day-and-night cycle. Desert wind, alpine snow, wheat gusts, layered ocean waves and reusable dolphins, and a luminescent forest with a reusable cover-to-cover gremlin each receive detailed art, motion, loss, audio, asset, performance, determinism, and readability requirements. Major cosmetic events use shared seed and time; harmless cosmetic desynchronization never affects match authority. Delivery proceeds from the shared framework and Wheat Field reference arena through Desert and Snow, Ocean, Mushroom Forest, and a final competitive release gate.'},
{id:'reaction-system',section:'Social & Reactions',title:'Curated five-slot reaction system',pages:'Feature Bible v1.0, pp. 1-8',sourceId:'reaction_system_v1',sourceFile:'Tap_Against_Me_Reaction_System_Feature_Bible_v1.0.pdf',sourceTitle:'Reaction System Feature Bible v1.0',status:'pending',summary:'Players collect animated TAM-authored reactions, equip five, and use a compact in-match wheel for sportsmanship and playful rivalry without text chat, uploaded imagery, input interruption, or gameplay advantage.',requirements:['A profile-owned collection equips exactly five valid unique reactions with order, favorite, source, rarity, preview, lock, recent-unlock, and filter metadata','A compact five-slot wheel supports slide or tap selection without pausing, covering critical information, or converting an unintended gameplay tap','A selected reaction appears in a protected character-side, profile-banner, or screen-edge region for approximately 1.5-2 seconds','Candidate match moments include pre-countdown, active play, mistake and item events, final seconds, and results; a valid late reaction may carry briefly into results','Friendly, competitive, taunt, emotional, hero, world-discovery, ranked, limited, and secret categories form the candidate taxonomy','Coin shop, achievements, ranked seasons, seasonal progression, Infinity discoveries, secrets, events, challenges, and character mastery preserve acquisition provenance','Infinity-exclusive reactions are earned by discovery and are automatically absent from direct-purchase offers','Launch content is curated and TAM-authored; unrestricted player images, free text, and hidden communication channels are prohibited','Facial animation, particles, sound, symbols, hero motion, entrances, exits, and rare variants obey visibility, flash, motion, density, audio, and performance budgets','Candidate anti-spam baseline: approximately three-second cooldown, rolling-window cap, and repeated-selection suppression','Opponent reactions and reaction sounds have separate mute controls; muting an opponent never blocks the local player’s own reactions','The server rejects unowned reaction IDs, invalid match states, cooldown/window violations, duplicates, and malformed events without interrupting play','Common, Uncommon, Rare, Epic, Legendary, and Secret are candidate rarity tiers; price reflects presentation quality, never competitive value','Duplicate conversion into coins, fragments, or crafting value remains an explicit open decision and may not create inventory clutter','Reactions never affect tap force, input validation, gravity, collision, pickups, matchmaking, rating, rewards, or outcomes','Analytics cover wheel opens, selection, send, suppression, visibility, unlock, equip, mute, repeated-use rate, match context, and frame/input/obstruction quality'],evidence:'Not started. The current website and implementation evidence contain no reaction definition catalog, ownership schema, five-slot loadout, in-match wheel, authoritative reaction event, cooldown enforcement, opponent mute, reaction-sound preference, or acquisition integration.',sourceExcerpt:'Each player owns a collection of animated emoji-style reactions and equips five reactions through their profile. During a match, a compact five-slot wheel allows slide or tap selection, then presents the reaction for roughly 1.5-2 seconds. Reactions come from the coin shop, achievements, competitive ranks, seasons, Infinity discoveries, secret interactions, events, challenges, and character mastery. Infinity-exclusive discoveries remain unavailable for direct purchase. The candidate anti-spam baseline uses an approximately three-second cooldown, a rolling-window cap, repeated-selection suppression, opponent mute, and separate reaction-sound control. Launch content remains TAM-authored, with no unrestricted player-uploaded imagery or free text. The system exists to support sportsmanship and playful rivalry without creating gameplay advantage, input interruption, harassment, clutter, or moderation debt.'}
];
const labels = { shipped: 'Shipped', partial: 'In progress', pending: 'Planned', concept: 'Under review' };
const statusMeaning = {
  shipped: 'Available in the current game foundation.',
  partial: 'A usable foundation exists, but the full feature described here is not complete.',
  pending: 'Approved or specified work that has not been implemented yet.',
  concept: 'A documented direction that still needs an explicit decision before implementation.'
};
