const sourceFiles = { legacy_bible: 'Tap_Against_Me_Original_Expanded_Bible.pdf', competitive_day_night: 'Tap_Against_Me_Competitive_Day_Night_Gravity_Bible.pdf', tam_game_design_full: 'Tap_Against_Me_TAM_Game_Design_Bible_v1.0.docx', game_design_addendum: 'Tap_Against_Me_Game_Design_Bible_Addendum.pdf', tam_game_bible: 'Tap_Against_Me_TAM_Game_Bible.docx', tam_design_bible: 'Tap_Against_Me_TAM_Design_Bible_v1.0.pdf', game_bible_v1: 'Tap_Against_Me_Game_Bible_v1.0.docx', game_design_v1: 'Tap_Against_Me_Game_Design_Bible_v1.0.pdf' };
const saved = JSON.parse(localStorage.getItem('tam-bible-status') || '{}');
const defaults = Object.fromEntries(systems.map((system) => [system.id, system.status]));
systems.forEach((system) => { if (saved[system.id]) system.status = saved[system.id]; });
let active = 'all';
const records = document.querySelector('#records');
const search = document.querySelector('#search');
const sectionNav = document.querySelector('#section-nav');
const corpus = window.TAM_CORPUS || [];
const masterBible = window.TAM_MASTER_BIBLE || { chapters: [] };
const ledgerTable = masterBible.chapters.find((chapter) => chapter.number === 42)?.blocks.find((block) => block.type === 'table');
const masterLedger = (ledgerTable?.rows || []).slice(1).map((row) => ({ feature: row[0], intent: row[1], design: row[2], evidence: row[3], gate: row[4] }));
