  const ranked = masterLedger.map((row) => ({ row, score: tokens.reduce((score, token) => score + (row.feature.toLowerCase().includes(token) ? 3 : 0) + (row.intent.toLowerCase().includes(token) ? 1 : 0), 0) })).sort((a, b) => b.score - a.score)[0];
